import React, { useState, useEffect } from 'react'
import axios from 'axios';
import InfiniteScroll from 'react-infinite-scroll-component'
import { Layout, Button, List, Divider, Avatar, Card, Input } from 'antd';
import { UserOutlined } from '@ant-design/icons'
import store from '../../Redux/store'
import { useNavigate } from 'react-router-dom'
import { useFriendList } from '../Layout/index'
import getContactListAction from '../../Redux/actionCreator/getContactListAction';
const { Content, Sider } = Layout;

const userId = localStorage.getItem('userId')

export default function Contacts() {
  const [isClick, setIsClick] = useState(false);
  const [isClickSearch, setIsClickSearch] = useState(false);
  const [search, setQuery] = useState('');
  const [searchResult, setSearchResult] = useState(null);
  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  const [firendList, setFriendList] = useState(store.getState().contactReducer.user);
  const [selectedUser, setSelectedUser] = useState(null);
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate();
  const { friendList_room, setFriendList_room } = useFriendList()

  useEffect(() => {
    LoadContactList()
  }, [])

  const handleAddFriends = () => {
    setIsClick(!isClick);
  }

  const handleEnterKey = (event) => {
    if (event.key === 'Enter') {
      SearchUser();
      setIsClickSearch(!isClickSearch);
      setQuery('')
    }
  }

  // 搜索好友
  const SearchUser = async () => {
    setSuccessMessage('');
    setErrorMessage('');
    try {
      const response = await axios.get(`http://localhost:4000/api/search?query=${query}`);
      setSearchResult(response.data);
      console.log(response.data)
    } catch (error) {
      console.error('搜索失败：', error)
    }
  }

  // 添加好友
  const AddFriends = async (friendId) => {
    try {
      const response = await axios.post('http://localhost:4000/api/addFriends',
        {
          userIdToAdd: friendId,
          currentUserId: userId
        });
      console.log(friendId, userId);
      const message = response.data.message;
      console.log(message);
      setSuccessMessage(message);
      LoadContactList();
    } catch (error) {
      setErrorMessage(`${error.message}`)
      console.error('添加好友失败', error);
    }
  }

  const LoadContactList = () => {
    setLoading(true)
    try {
      if (store.getState().contactReducer.user.length === 0) {
        // 如果联系人列表为空，才触发加载操作
        store.dispatch(getContactListAction());
        store.subscribe(() => {
          setFriendList(store.getState().contactReducer.user)
        })
      }
    } catch (error) {
      console.error('加载联系人列表时出错：', error);
    } finally {
      setLoading(false)
    }
  };

  const hanleChatButtonClick = async () => {
    try {
      const userId1 = userId;
      const userId2 = selectedUser.username;

      const response = await axios.post('http://localhost:4000/api/createRoom', {
        userId1,
        userId2
      });

      if (response.status === 200) {
        const roomId = response.data.roomId;
        if (!friendList_room.includes(selectedUser.username)) {
          setFriendList_room((prevFriendList) => [...prevFriendList, selectedUser.username]);
        }
        navigate(`/layout/chat?selectedUser=${userId2}&roomId=${roomId}`);
      }
    } catch (error) {
      console.error('发生错误：', error);
    }
  }

  const UserDetails = ({ user }) => {
    if (!user) {
      return null;
    }
    return (
      <div style={{
        display: 'flex',
        height: '100%',
        textAlign: 'center',
        marginLeft: '20px',
        marginRight: '20px',
        backgroundColor: "transparent",
        border: '1px solid rgba(140, 140, 140, 0.35)',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center'
      }}>
        <div
          style={{
            marginBottom: '280px',
            fontSize: '50px'
          }}
        >{user.username}</div>
        <Button
          ghost
          size={'large'}
          style={{ width: "100px", marginBottom: "20px" }}
          onClick={hanleChatButtonClick}
        >Chat</Button>
      </div>
    )
  }

  const NullUser = () => {
    return (
      <div style={{
        display: 'flex',
        height: '100%',
        textAlign: 'center',
        marginLeft: '20px',
        marginRight: '20px',
        backgroundColor: "transparent",
        border: '1px solid rgba(140, 140, 140, 0.35)',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center'
      }}>
        <div
          style={{
            fontSize: '50px',
            color: 'rgb(100,100,100)'
          }}
        >CHAT</div>
      </div>
    )
  }

  const ContentPage = () => {
    useEffect(() => {
      if (isClick === false && selectedUser === null) {
        // 在此处理状态更新
      }

      if (isClick) {
        setSelectedUser(null);
        // 在此处理状态更新
      }

      if (selectedUser) {
        setIsClick(false);
        // 在此处理状态更新
      }
    }, []);

    if (isClick === false && selectedUser === null) {
      return <NullUser />;
    }

    if (isClick) {
      return <SearchUserPage />;
    }

    if (selectedUser) {
      return <UserDetails user={selectedUser} />;
    }
  }

  const SearchUserPage = () => {
    return (
      <Card
        style={{
          display: 'flex',
          height: '100%',
          marginLeft: '20px',
          marginRight: '20px',
          backgroundColor: "transparent",
          border: '1px solid rgba(140, 140, 140, 0.35)',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'space-around'
        }}
      >
        <Input
          placeholder='Search User'
          size='large'
          style={{ width: '500px', height: '50px' }}
          // onChange={(e) => setQuery(e.target.value)}
          suffix={<UserOutlined />}
          value={query}
          onPressEnter={handleEnterKey}
        />
        {searchResult &&
          <Card
            style={{ width: '500px', marginTop: '20px', height: '280px', backgroundColor: '' }}
          >
            <Avatar style={{ margin: '30px', backgroundColor: 'rgb(0,150,255)' }} size={70}>{searchResult[0]?.username}</Avatar>
            <Card.Meta
              description={searchResult[0]?.username}
              title=''
            />
            <Button onClick={AddFriends} style={{ marginTop: '10px', border: "0", backgroundColor: 'rgb(100,100,100,0.5)' }}>ADD</Button>
          </Card>}
      </Card>
    )
  }

  return (
    <Content
      style={{
        padding: '0 50px',
        marginTop: "30px"
      }}
    >
      <Layout
        style={{
          height: "100%",
          padding: '24px 0',
          backgroundColor: "rgb(255,255,255,0.5)",
          backdropFilter: "blur(10px)",
          WebkitBackdropFilter: "blur(10px)"
        }}
      >
        <Sider
          width={300}
          style={{
            backgroundColor: "transparent",
            fontSize: '20px'
          }}
        >
          <div
            id="scrollableDiv"
            style={{
              height: "100%",
              overflow: 'auto',
              padding: '0 16px',
              marginLeft: '20px',
              border: '1px solid rgba(140, 140, 140, 0.35)',
            }}
          >
            <Button size='large' onClick={handleAddFriends} ghost style={{ width: '100%', borderColor: 'rgba(140, 140, 140, 0.35)', marginTop: '10px' }}>ADD</Button>
            <InfiniteScroll
              dataLength={firendList.length}
              next={LoadContactList}
              hasMore={firendList.length < 50}
              endMessage={<Divider plain>It is all, nothing more 🤐</Divider>}
              scrollableTarget="scrollableDiv"
            >
              <List
                dataSource={firendList}
                renderItem={(item) => (
                  <List.Item >
                    <List.Item.Meta
                      avatar={<Avatar size={30} style={{ backgroundColor: "rgb(0,150,255)" }}>{item.username}</Avatar>}
                      title={item.username}
                    />
                    <div onClick={
                      () => {
                        setIsClick(false)
                        setSelectedUser(item)
                      }}>Content</div>
                  </List.Item>
                )}
              />
            </InfiniteScroll>
          </div>
        </Sider>
        <Content>
          <ContentPage />
        </Content>
      </Layout>
    </Content>
  )
}
